const data = $input.first().json;
const body = data.body || data;

// Filtrar apenas MESSAGES_UPSERT
if (body.event !== 'messages.upsert') {
  return [];
}

const instance = body.instance;
const msgData = body.data;
if (!msgData || !msgData.key) return [];

const key = msgData.key;
const remoteJid = key.remoteJid || '';
const fromMe = key.fromMe || false;

// Ignorar mensagens de grupo
if (remoteJid.includes('@g.us')) return [];

// Extrair conteúdo
let content = '';
let messageType = 'text';
let mediaUrl = '';

const msg = msgData.message || {};
if (msg.conversation) {
  content = msg.conversation;
} else if (msg.extendedTextMessage) {
  content = msg.extendedTextMessage.text || '';
} else if (msg.imageMessage) {
  content = msg.imageMessage.caption || '';
  messageType = 'image';
  mediaUrl = msg.imageMessage.url || '';
} else if (msg.videoMessage) {
  content = msg.videoMessage.caption || '';
  messageType = 'video';
  mediaUrl = msg.videoMessage.url || '';
} else if (msg.audioMessage) {
  messageType = 'audio';
  mediaUrl = msg.audioMessage.url || '';
} else if (msg.documentMessage) {
  content = msg.documentMessage.fileName || '';
  messageType = 'document';
  mediaUrl = msg.documentMessage.url || '';
} else {
  // Tipo não suportado (sticker, location, etc)
  return [];
}

const contactPhone = remoteJid.replace('@s.whatsapp.net', '');
const contactName = msgData.pushName || contactPhone;

return [{
  json: {
    instance_name: instance,
    remote_jid: remoteJid,
    from_me: fromMe,
    message_type: messageType,
    content: content,
    media_url: mediaUrl || null,
    contact_name: contactName,
    contact_phone: contactPhone
  }
}];

const parsed = $('1. Parse Mensagem').first().json;
const instArr = $('2. Buscar Instância').first().json;
const inst = Array.isArray(instArr) ? instArr[0] : instArr;

return [{
  json: {
    ...parsed,
    instance_id: inst.id,
    user_id: inst.user_id
  }
}];

const parsed = $('3. Juntar Dados').first().json;
const convArr = $('4. Buscar Conversa').first().json;
const conv = Array.isArray(convArr) ? convArr[0] : convArr;
const conversationId = conv?.id || null;

return [{
  json: {
    ...parsed,
    conversation_id: conversationId,
    needs_new: !conversationId
  }
}];

