const prepared = $('5. Preparar').first().json;
let convId = prepared.conversation_id;

// Se criou nova conversa, pegar o ID retornado
if (!convId) {
  try {
    const created = $('6a. Criar Conversa').first().json;
    const arr = Array.isArray(created) ? created[0] : created;
    convId = arr?.id || null;
  } catch(e) {}
}

if (!convId) {
  throw new Error('Sem conversation_id para salvar mensagem');
}

return [{
  json: {
    conversation_id: convId,
    remote_jid: prepared.remote_jid,
    from_me: prepared.from_me,
    message_type: prepared.message_type,
    content: prepared.content || '',
    media_url: prepared.media_url || null,
    status: prepared.from_me ? 'sent' : 'delivered'
  }
}];
